function getDeviceReading(type, payload) {
    if (!payload) return null;
    if (type === 'lamp' || type === 'plug') {
        return payload.output === 100 ? "on": "off";
    } else if (type === 'presence_sensor') {
        return payload.input === 100 ? "detected" : "not_detected";
    } else if (type === 'door_sensor') {
        return payload.input === 100 ? "open" : "closed";
    }

    return payload.output === 100 ? 'on' : 'off';
}

